"use client"

import { useState } from "react"
import { useRouter } from "next/navigation"
import { useCartStore } from "@/store/cart"
import { StepIndicator } from "@/components/checkout/StepIndicator"
import { OrderSummary } from "@/components/checkout/OrderSummary"
import { AddressStep } from "@/components/checkout/AddressStep"
import { ShippingStep } from "@/components/checkout/ShippingStep"
import { PaymentStep } from "@/components/checkout/PaymentStep"
import { Button } from "@/components/ui/button"
import Link from "next/link"
import type { ShippingQuote } from "@/lib/melhorenvio"

type Address = {
  id: string; street: string; number: string; complement?: string | null
  neighborhood: string; city: string; state: string; zipCode: string; isDefault: boolean
}

export default function CheckoutPage() {
  const router = useRouter()
  const items = useCartStore((s) => s.items)
  const [step, setStep] = useState<1 | 2 | 3>(1)
  const [address, setAddress] = useState<Address | null>(null)
  const [shipping, setShipping] = useState<ShippingQuote | null>(null)

  if (items.length === 0) {
    return (
      <div className="mx-auto max-w-lg px-4 py-24 flex flex-col items-center gap-5">
        <span className="text-7xl opacity-25">🛒</span>
        <p className="font-black text-xl text-brown-dark">Carrinho vazio</p>
        <p className="font-semibold text-brown-muted text-sm">Adicione produtos antes de finalizar a compra.</p>
        <Button asChild><Link href="/produtos">Ver loja</Link></Button>
      </div>
    )
  }

  return (
    <div className="mx-auto max-w-5xl px-4 md:px-8 py-10">
      {/* Título + progress */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-10">
        <h1 className="font-black text-[28px] text-brown-dark">Finalizar compra</h1>
        <StepIndicator current={step} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Formulário */}
        <div className="lg:col-span-2 bg-white rounded-card p-6 shadow-[0_2px_16px_rgba(61,43,31,0.07)]">
          {step === 1 && (
            <AddressStep
              onNext={(addr) => {
                setAddress(addr)
                setStep(2)
              }}
            />
          )}
          {step === 2 && address && (
            <ShippingStep
              address={address}
              onNext={(opt) => {
                setShipping(opt)
                setStep(3)
              }}
              onBack={() => setStep(1)}
            />
          )}
          {step === 3 && address && shipping && (
            <PaymentStep
              address={address}
              shipping={shipping}
              onBack={() => setStep(2)}
            />
          )}
        </div>

        {/* Resumo */}
        <div>
          <OrderSummary shippingCost={shipping?.price} />
        </div>
      </div>
    </div>
  )
}

"use client"

import Link from "next/link"
import { ShoppingBag, ArrowLeft } from "lucide-react"
import { useCartStore } from "@/store/cart"
import { CartItem } from "@/components/cart/CartItem"
import { Button } from "@/components/ui/button"
import { formatPrice } from "@/lib/utils"
import { useState } from "react"
import { applyCoupon } from "@/actions/checkout"

export default function CarrinhoPage() {
  const { items, subtotal, clearCart } = useCartStore()
  const [couponCode, setCouponCode] = useState("")
  const [couponResult, setCouponResult] = useState<{ discount: number; code: string } | null>(null)
  const [couponError, setCouponError] = useState("")
  const [loadingCoupon, setLoadingCoupon] = useState(false)

  const sub = subtotal()
  const discount = couponResult?.discount ?? 0
  const total = sub - discount

  async function handleCoupon() {
    if (!couponCode.trim()) return
    setLoadingCoupon(true)
    setCouponError("")
    const result = await applyCoupon(couponCode, sub)
    setLoadingCoupon(false)
    if ("error" in result) {
      setCouponError(result.error)
    } else {
      setCouponResult({ discount: result.discount, code: couponCode.toUpperCase() })
    }
  }

  if (items.length === 0) {
    return (
      <div className="mx-auto max-w-3xl px-4 py-20 flex flex-col items-center gap-5">
        <span className="text-8xl opacity-25">🛒</span>
        <h1 className="font-black text-2xl text-brown-dark">Seu carrinho está vazio</h1>
        <p className="font-semibold text-brown-muted">Explore nossa loja e encontre produtos incríveis!</p>
        <Button asChild><Link href="/produtos">Ver loja</Link></Button>
      </div>
    )
  }

  return (
    <div className="mx-auto max-w-5xl px-4 md:px-8 py-10">
      <div className="flex items-center gap-3 mb-8">
        <Link href="/produtos" className="text-brown-muted hover:text-primary transition-colors">
          <ArrowLeft size={20} />
        </Link>
        <h1 className="font-black text-[28px] text-brown-dark">Carrinho</h1>
        <span className="bg-primary/10 text-primary font-black text-sm px-3 py-1 rounded-pill">
          {items.length} {items.length === 1 ? "item" : "itens"}
        </span>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Lista de itens */}
        <div className="lg:col-span-2 bg-white rounded-card p-6 shadow-[0_2px_16px_rgba(61,43,31,0.07)]">
          {items.map((item) => (
            <CartItem key={`${item.productId}-${item.size}`} item={item} />
          ))}
          <button
            onClick={() => clearCart()}
            className="mt-4 text-xs font-bold text-brown-muted hover:text-red-400 transition-colors"
          >
            Limpar carrinho
          </button>
        </div>

        {/* Resumo */}
        <div className="bg-white rounded-card p-6 shadow-[0_2px_16px_rgba(61,43,31,0.07)] h-fit sticky top-24 space-y-5">
          <p className="font-black text-[17px] text-brown-dark">Resumo do pedido</p>

          {/* Cupom */}
          {couponResult ? (
            <div className="flex items-center justify-between bg-primary/10 rounded-lg px-3 py-2">
              <div>
                <p className="font-extrabold text-sm text-primary">{couponResult.code}</p>
                <p className="text-xs font-bold text-brown-muted">− {formatPrice(couponResult.discount)}</p>
              </div>
              <button
                onClick={() => setCouponResult(null)}
                className="text-xs font-bold text-brown-muted hover:text-red-400"
              >
                Remover
              </button>
            </div>
          ) : (
            <div className="flex gap-2">
              <input
                value={couponCode}
                onChange={(e) => setCouponCode(e.target.value.toUpperCase())}
                placeholder="Cupom de desconto"
                className="flex-1 border border-bg-nude rounded-lg px-3 py-2 text-sm font-bold text-brown-dark placeholder:text-brown-muted outline-none focus:border-primary"
              />
              <Button
                variant="ghost"
                size="sm"
                onClick={handleCoupon}
                disabled={loadingCoupon || !couponCode}
              >
                {loadingCoupon ? "..." : "Aplicar"}
              </Button>
            </div>
          )}
          {couponError && <p className="text-xs font-bold text-red-500">{couponError}</p>}

          {/* Totais */}
          <div className="space-y-2 border-t border-bg-nude pt-4">
            <div className="flex justify-between text-sm font-semibold text-brown-muted">
              <span>Subtotal</span>
              <span>{formatPrice(sub)}</span>
            </div>
            {discount > 0 && (
              <div className="flex justify-between text-sm font-bold text-primary">
                <span>Desconto</span>
                <span>− {formatPrice(discount)}</span>
              </div>
            )}
            <div className="flex justify-between text-sm font-semibold text-brown-muted">
              <span>Frete</span>
              <span className="text-secondary font-bold">Calculado no checkout</span>
            </div>
            <div className="flex justify-between font-black text-lg text-brown-dark border-t border-bg-nude pt-3">
              <span>Total</span>
              <span>{formatPrice(total)}</span>
            </div>
          </div>

          <Button size="lg" className="w-full" asChild>
            <Link href="/checkout">
              <ShoppingBag size={16} /> Finalizar compra
            </Link>
          </Button>

          <Link href="/produtos" className="block text-center text-sm font-bold text-brown-muted hover:text-primary transition-colors">
            ← Continuar comprando
          </Link>
        </div>
      </div>
    </div>
  )
}

"use client"

import Link from "next/link"
import { useQuery } from "@tanstack/react-query"
import { useSession } from "next-auth/react"
import { ShoppingBag, ArrowRight } from "lucide-react"
import { OrderStatusBadge } from "@/components/account/OrderStatusBadge"
import { Skeleton } from "@/components/ui/skeleton"
import { Button } from "@/components/ui/button"
import { formatPrice } from "@/lib/utils"

async function fetchOrders() {
  const res = await fetch("/api/orders?limit=3")
  if (!res.ok) return { data: [], meta: { total: 0 } }
  return res.json()
}

export default function ContaDashboardPage() {
  const { data: session } = useSession()
  const { data, isLoading } = useQuery({ queryKey: ["orders-preview"], queryFn: fetchOrders })

  const orders = data?.data ?? []
  const total  = data?.meta?.total ?? 0
  const firstName = session?.user.name?.split(" ")[0] ?? "Cliente"

  return (
    <div className="space-y-8">
      {/* Boas-vindas */}
      <div>
        <h1 className="font-black text-[28px] text-brown-dark">
          Olá, {firstName}! 👋
        </h1>
        <p className="font-semibold text-brown-muted mt-1">
          Gerencie seus pedidos, dados e endereços.
        </p>
      </div>

      {/* Card atacado pendente */}
      {session?.user.role === "WHOLESALE" && !session.user.wholesaleApproved && (
        <div className="bg-accent/20 border border-accent rounded-card p-4 flex items-start gap-3">
          <span className="text-2xl">⏳</span>
          <div>
            <p className="font-extrabold text-sm text-brown-dark">Conta atacado em análise</p>
            <p className="font-semibold text-xs text-brown-muted mt-1">
              Seu cadastro de revendedor está sendo analisado. Em até 2 dias úteis você receberá a confirmação por e-mail.
            </p>
          </div>
