      )}

      {/* Últimos pedidos */}
      <div className="bg-white rounded-card shadow-[var(--shadow-card)] p-6">
        <div className="flex items-center justify-between mb-5">
          <div className="flex items-center gap-2">
            <ShoppingBag size={18} className="text-primary" />
            <h2 className="font-black text-[17px] text-brown-dark">Últimos pedidos</h2>
          </div>
          {total > 3 && (
            <Link href="/minha-conta/pedidos" className="flex items-center gap-1 text-xs font-extrabold text-primary hover:underline">
              Ver todos <ArrowRight size={12} />
            </Link>
          )}
        </div>

        {isLoading && (
          <div className="space-y-3">
            {[1, 2, 3].map((i) => <Skeleton key={i} className="h-16 w-full" />)}
          </div>
        )}

        {!isLoading && orders.length === 0 && (
          <div className="text-center py-10 space-y-3">
            <span className="text-5xl block opacity-25">📦</span>
            <p className="font-extrabold text-brown-dark">Nenhum pedido ainda</p>
            <Button asChild size="sm"><Link href="/produtos">Explorar loja</Link></Button>
          </div>
        )}

        {!isLoading && orders.length > 0 && (
          <div className="divide-y divide-bg-nude">
            {orders.map((order: any) => (
              <Link
                key={order.id}
                href={`/minha-conta/pedidos/${order.id}`}
                className="flex items-center justify-between py-3 hover:bg-bg-blush -mx-2 px-2 rounded-lg transition-colors"
              >
                <div>
                  <p className="font-extrabold text-sm text-brown-dark">
                    #{order.id.slice(-8).toUpperCase()}
                  </p>
                  <p className="font-semibold text-xs text-brown-muted mt-0.5">
                    {new Date(order.createdAt).toLocaleDateString("pt-BR")} ·{" "}
                    {order._count.items} {order._count.items === 1 ? "item" : "itens"}
                  </p>
                </div>
                <div className="flex items-center gap-3">
                  <OrderStatusBadge status={order.status} />
                  <span className="font-black text-[15px] text-brown-dark">
                    {formatPrice(Number(order.total))}
                  </span>
                  <ArrowRight size={14} className="text-brown-muted" />
                </div>
              </Link>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

"use client"

import Link from "next/link"
import { useState } from "react"
import { useQuery } from "@tanstack/react-query"
import { ArrowRight, Package } from "lucide-react"
import { OrderStatusBadge } from "@/components/account/OrderStatusBadge"
import { Skeleton } from "@/components/ui/skeleton"
import { Button } from "@/components/ui/button"
import { formatPrice } from "@/lib/utils"
import Image from "next/image"

async function fetchOrders(page: number) {
  const res = await fetch(`/api/orders?page=${page}&limit=10`)
  if (!res.ok) return { data: [], meta: { total: 0, pages: 0 } }
  return res.json()
}

const METHOD_LABEL: Record<string, string> = {
  pix: "Pix", credit_card: "Cartão de crédito", boleto: "Boleto",
}

export default function PedidosPage() {
  const [page, setPage] = useState(1)
  const { data, isLoading } = useQuery({
    queryKey: ["orders", page],
    queryFn: () => fetchOrders(page),
  })

  const orders = data?.data ?? []
  const meta   = data?.meta ?? { total: 0, pages: 0 }

  return (
    <div className="space-y-6">
      <h1 className="font-black text-[26px] text-brown-dark">Meus pedidos</h1>

      {isLoading && (
        <div className="space-y-3">
          {Array.from({ length: 5 }).map((_, i) => (
            <Skeleton key={i} className="h-28 w-full rounded-card" />
          ))}
        </div>
      )}

      {!isLoading && orders.length === 0 && (
        <div className="text-center py-16 bg-white rounded-card shadow-[var(--shadow-card)] space-y-4">
          <Package size={48} className="mx-auto text-brown-muted opacity-30" />
          <p className="font-extrabold text-lg text-brown-dark">Nenhum pedido ainda</p>
          <p className="font-semibold text-sm text-brown-muted">Seu histórico aparecerá aqui após a primeira compra.</p>
          <Button asChild><Link href="/produtos">Explorar loja</Link></Button>
        </div>
      )}

      {!isLoading && orders.length > 0 && (
        <div className="space-y-3">
          {orders.map((order: any) => {
            const firstItem = order.items?.[0]
            const itemCount = order._count?.items ?? order.items?.length ?? 0
            return (
              <Link
                key={order.id}
                href={`/minha-conta/pedidos/${order.id}`}
                className="block bg-white rounded-card shadow-[var(--shadow-card)] p-5 hover:shadow-[0_6px_24px_rgba(61,43,31,0.12)] transition-shadow"
              >
                <div className="flex items-start gap-4">
                  {/* Thumb do primeiro item */}
                  <div className="relative w-16 h-16 rounded-lg overflow-hidden bg-bg-blush shrink-0">
                    {firstItem?.product?.images?.[0]?.url ? (
                      <Image src={firstItem.product.images[0].url} alt={firstItem.product.name} fill sizes="64px" className="object-cover" />
                    ) : (
                      <span className="w-full h-full flex items-center justify-center text-2xl">👕</span>
                    )}
                  </div>

                  {/* Info */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between gap-2 flex-wrap">
                      <p className="font-extrabold text-sm text-brown-dark">
                        Pedido #{order.id.slice(-8).toUpperCase()}
                      </p>
                      <OrderStatusBadge status={order.status} />
                    </div>
                    <p className="font-semibold text-xs text-brown-muted mt-1">
                      {new Date(order.createdAt).toLocaleDateString("pt-BR", { day: "2-digit", month: "long", year: "numeric" })}
                      {" · "}{itemCount} {itemCount === 1 ? "item" : "itens"}
                      {order.paymentMethod && ` · ${METHOD_LABEL[order.paymentMethod] ?? order.paymentMethod}`}
                    </p>
                    <div className="flex items-center justify-between mt-3">
                      <span className="font-black text-[17px] text-primary">
                        {formatPrice(Number(order.total))}
                      </span>
                      <span className="flex items-center gap-1 text-xs font-extrabold text-brown-muted hover:text-primary">
                        Ver detalhes <ArrowRight size={12} />
                      </span>
                    </div>
                  </div>
                </div>
              </Link>
            )
          })}
        </div>
      )}

      {/* Paginação simples */}
      {meta.pages > 1 && (
        <div className="flex justify-center gap-2 pt-2">
          <Button variant="ghost" size="sm" disabled={page <= 1} onClick={() => setPage(p => p - 1)}>← Anterior</Button>
          <span className="font-bold text-sm text-brown-muted flex items-center">{page} / {meta.pages}</span>
          <Button variant="ghost" size="sm" disabled={page >= meta.pages} onClick={() => setPage(p => p + 1)}>Próximo →</Button>
        </div>
      )}
    </div>
  )
}

"use client"

import { useState } from "react"
import Link from "next/link"
import { Eye, EyeOff, Store, User } from "lucide-react"
import { AuthCard } from "@/components/auth/AuthCard"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"

type Role = "RETAIL" | "WHOLESALE"

export default function CadastroPage() {
  const [role, setRole]         = useState<Role>("RETAIL")
  const [name, setName]         = useState("")
  const [email, setEmail]       = useState("")
  const [password, setPassword] = useState("")
  const [cnpj, setCnpj]         = useState("")
  const [showPass, setShowPass] = useState(false)
  const [loading, setLoading]   = useState(false)
  const [error, setError]       = useState("")
  const [success, setSuccess]   = useState("")

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setLoading(true)
    setError("")
    setSuccess("")

    const res = await fetch("/api/auth/register", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, email, password, role, ...(cnpj && { cnpj }) }),
    })

    setLoading(false)
    const json = await res.json()

    if (!res.ok) {
      setError(json.error ?? "Erro ao criar conta. Tente novamente.")
      return
    }

    setSuccess(json.message)
  }

  if (success) {
    return (
      <AuthCard title="Cadastro realizado!">
        <div className="text-center space-y-5">
          <span className="text-6xl block">🎉</span>
          <p className="font-semibold text-brown-mid leading-relaxed">{success}</p>
          <Button asChild className="w-full">
            <Link href="/login">Fazer login</Link>
          </Button>
        </div>
      </AuthCard>
    )
  }

  return (
    <AuthCard title="Criar conta" subtitle="Junte-se à família Playbekids!">
      <form onSubmit={handleSubmit} className="space-y-5">

        {/* Seletor de tipo de conta */}
        <div>
          <p className="text-xs font-black uppercase tracking-[0.1em] text-brown-muted mb-3">
            Tipo de conta
          </p>
          <div className="grid grid-cols-2 gap-3">
            {([
              { id: "RETAIL",    label: "Comprador",  sub: "Para minha família", icon: User  },
              { id: "WHOLESALE", label: "Revendedor", sub: "Atacado / lojista",   icon: Store },
            ] as { id: Role; label: string; sub: string; icon: typeof User }[]).map(
              ({ id, label, sub, icon: Icon }) => (
                <button
                  key={id}
                  type="button"
                  onClick={() => setRole(id)}
                  className={cn(
                    "flex flex-col items-center gap-1.5 p-4 rounded-card border-2 transition-all",
                    role === id
                      ? "border-primary bg-primary/5"
                      : "border-bg-nude bg-white hover:border-brown-muted"
                  )}
                >
                  <div className={cn(
                    "w-10 h-10 rounded-lg flex items-center justify-center",
                    role === id ? "bg-primary text-white" : "bg-bg-blush text-brown-muted"
                  )}>
                    <Icon size={18} />
                  </div>
                  <span className="font-extrabold text-sm text-brown-dark">{label}</span>
                  <span className="font-semibold text-[11px] text-brown-muted">{sub}</span>
                </button>
              )
            )}
          </div>
        </div>

        <Input
          label="Nome completo"
          id="name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          placeholder="João Silva"
          required
          autoComplete="name"
        />

        <Input
          label="E-mail"
          id="email"
          type="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          placeholder="seu@email.com"
          required
          autoComplete="email"
        />

        <div className="relative">
          <Input
            label="Senha"
            id="password"
            type={showPass ? "text" : "password"}
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="Mínimo 8 caracteres"
            required
            minLength={8}
            autoComplete="new-password"
          />
          <button
            type="button"
            onClick={() => setShowPass((v) => !v)}
            className="absolute right-3 bottom-3 text-brown-muted hover:text-brown-dark transition-colors"
          >
            {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
          </button>
        </div>

        {role === "WHOLESALE" && (
          <div className="space-y-3 bg-bg-blush rounded-lg p-4 border border-bg-nude">
            <p className="text-xs font-black uppercase tracking-wider text-brown-muted">
              Dados de atacado
            </p>
            <Input
              label="CNPJ (opcional)"
              value={cnpj}
              onChange={(e) => setCnpj(e.target.value)}
              placeholder="00.000.000/0001-00"
            />
            <p className="text-xs font-semibold text-brown-muted leading-relaxed">
              ⚠️ Contas de atacado são aprovadas manualmente em até 2 dias úteis.
            </p>
          </div>
        )}

        {error && (
          <p className="text-sm font-bold text-red-500 bg-red-50 rounded-lg px-3 py-2">
            {error}
          </p>
        )}

        <Button type="submit" size="lg" className="w-full" disabled={loading}>
          {loading ? "Criando conta..." : "Criar conta"}
        </Button>

        <p className="text-center text-sm font-semibold text-brown-muted">
          Já tem conta?{" "}
          <Link href="/login" className="font-extrabold text-primary hover:underline">
            Entrar
          </Link>
        </p>
      </form>
    </AuthCard>
  )
}

